const row = $input.item.json;
// Use .item (not .first()) to get the current item's trigger data
const email = $('Trigger').item.json.email_address;
return { json: {
  cache_hit: row.cache_hit === true,
  email: email,
  email_address: email,
  cached_result: row.cache_hit ? row : null
}};

const { email, cached_result: c } = $input.item.json;
const score = [c.is_valid, !c.is_disposable, (c.mx_records||[]).length>0,
               c.smtp_result==='valid', !c.is_catch_all]
               .filter(Boolean).length * 20;
return { json: {
  email, is_valid: c.is_valid, is_disposable: c.is_disposable,
  is_catch_all: c.is_catch_all, has_mx: (c.mx_records||[]).length > 0,
  smtp_result: c.smtp_result, confidence_score: score,
  from_cache: true
}};

const net = require('net');
const prev = $('Full Verify').item.json;
const dnsResp = $input.item.json;

// n8n may return the DNS response body as a string in dnsResp.data
// (happens when Content-Type is application/dns-json, not application/json)
let dnsJson = dnsResp;
if (!Array.isArray(dnsResp.Answer) && dnsResp.data && typeof dnsResp.data === 'string') {
  try { dnsJson = JSON.parse(dnsResp.data); } catch (e) {}
}

// Parse MX records
const answers = Array.isArray(dnsJson.Answer) ? dnsJson.Answer : [];
const mx_records = answers
  .filter(a => a.type === 15)
  .map(a => {
    const parts = a.data.split(' ');
    return { priority: parseInt(parts[0]) || 10, exchange: parts[1]?.replace(/\.$/, '') };
  })
  .sort((a, b) => a.priority - b.priority);

const has_mx = mx_records.length > 0;

if (prev.skip_smtp || !has_mx) {
  return { json: { ...prev, mx_records, has_mx, smtp_result: has_mx ? 'skipped' : 'no_mx', is_catch_all: false }};
}

const mxHost = mx_records[0].exchange;
const { email } = prev;

const smtpVerify = () => new Promise(resolve => {
  const TIMEOUT = 10000;
  const sock = net.createConnection({ host: mxHost, port: 25 });
  let buf = '', step = 0;

  const done = (res, ca = false) => {
    clearTimeout(timer);
    sock.destroy();
    resolve({ result: res, catch_all: ca });
  };

  const timer = setTimeout(() => done('timeout'), TIMEOUT);

  sock.on('data', d => {
    buf += d.toString();
    let nl;
    while ((nl = buf.indexOf('\n')) !== -1) {
      const line = buf.slice(0, nl + 1).trim();
      buf = buf.slice(nl + 1);
      if (step === 0 && line.startsWith('220'))  { sock.write('EHLO n8n.verify\r\n'); step = 1; }
      else if (step === 1 && line.startsWith('250') && !line.includes('-')) {
        sock.write(`MAIL FROM:<noreply@n8n.verify>\r\n`); step = 2;
      }
      else if (step === 2 && line.startsWith('250')) { sock.write(`RCPT TO:<${email}>\r\n`); step = 3; }
      else if (step === 3) {
        if (/^2[0-9]{2}/.test(line)) {
          sock.write(`RCPT TO:<probe_${Date.now()}@${email.split('@')[1]}>\r\n`);
          step = 4;
        } else { done('invalid'); }
      }
      else if (step === 4) {
        const catch_all = /^2[0-9]{2}/.test(line);
        done('valid', catch_all);
      }
    }
  });

  sock.on('error', () => done('error'));
  sock.on('close', () => { if (step < 3) done('unknown'); });
});

const smtp = await smtpVerify();
return { json: {
  ...prev, mx_records, has_mx,
  smtp_result: smtp.result,
  is_catch_all: smtp.catch_all
}};

const d = $input.item.json;
const { email, valid_syntax, is_disposable, has_mx, smtp_result, is_catch_all } = d;

// Confidence score 0-100
let score = 0;
if (valid_syntax)               score += 10;
if (!is_disposable)             score += 20;
if (has_mx)                     score += 20;
if (smtp_result === 'valid')    score += 35;
if (!is_catch_all && has_mx)    score += 15;

// is_valid: syntax ok + not disposable + has MX + SMTP explicitly confirmed + not catch-all
const is_valid = valid_syntax && !is_disposable && has_mx && smtp_result === 'valid' && !is_catch_all;

return { json: {
  email,
  domain:           d.domain,
  is_valid,
  is_disposable:    is_disposable || false,
  is_catch_all:     is_catch_all  || false,
  has_mx:           has_mx        || false,
  smtp_result:      smtp_result   || 'unknown',
  mx_records:       d.mx_records  || [],
  confidence_score: score,
  from_cache:       false
}};

// Re-read from Build Result since Write Cache item only has HTTP response
const d = $('Build Result').item.json;
return { json: {
  email: d.email, is_valid: d.is_valid, is_disposable: d.is_disposable,
  is_catch_all: d.is_catch_all, has_mx: d.has_mx, smtp_result: d.smtp_result,
  confidence_score: d.confidence_score, from_cache: false
}};

const d = $input.item.json;
return { json: {
  email: d.email,
  is_valid: d.is_valid,
  is_disposable: d.is_disposable,
  is_catch_all: d.is_catch_all,
  has_mx: d.has_mx,
  smtp_result: d.smtp_result,
  confidence_score: d.confidence_score,
  from_cache: true
}};
